def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.25:
            base_score = np.power((1 - ratio), 4) + np.sin(ratio * 2 * np.pi) * 0.7
        elif 0.25 <= ratio < 0.5:
            base_score = np.exp(-ratio) * 4 + np.cos(ratio * 7) - np.sqrt(ratio) * 0.9
        elif 0.5 <= ratio < 0.75:
            base_score = (np.tanh(5 * (ratio - 0.5)) * 3) + np.log1p(ratio * 5) - (ratio ** 2)
        else:
            base_score = (np.sin(ratio * 8) * np.exp(-ratio)) + 1.5
        penalty = 0
        for j in range(1, 8):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.08:
                penalty += frac * (3 / j)
            elif 0.08 <= frac < 0.25:
                penalty += np.sqrt(frac) * (j / 5)
            elif 0.25 <= frac < 0.5:
                penalty += np.log1p(frac * j) / (j + 2)
            else:
                penalty += (frac / (j + 1)) ** 1.5
        extra_penalty = 0
        for k in range(1, 6):
            threshold = 0.4 * k
            if ratio > threshold:
                decay = np.exp(-k * (ratio - threshold))
                extra_penalty += decay * (k ** 2) / (ratio + 0.1)
            else:
                extra_penalty += np.log1p(k * ratio + 2) / (k + 3)
        complexity_factor = 0
        for m in range(1, 5):
            if m % 2 == 0:
                complexity_factor += (np.sin(m * ratio * np.pi) + np.cos(item / (capacity + m))) / m
            else:
                complexity_factor += (np.tanh(ratio * m) * np.sqrt(item)) / (m + 1)
        if capacity % 3 == 0:
            priorities[i] = base_score + penalty * 1.2 + extra_penalty * 0.9 + complexity_factor
        else:
            priorities[i] = base_score + penalty * 1.5 + extra_penalty * 1.1 + complexity_factor * 0.8
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
